import React, { useState, useEffect, useMemo, useRef } from 'react';

const Icon = ({ name }) => {
  const icons = {
    telegram: <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm4.64 6.8c-.15 1.58-.8 5.42-1.13 7.19-.14.75-.42 1-.68 1.03-.58.05-1.02-.38-1.58-.75-.88-.58-1.38-.94-2.23-1.5-.99-.65-.35-1.01.22-1.59.15-.15 2.71-2.48 2.76-2.69.01-.03.01-.14-.07-.2-.08-.06-.19-.04-.27-.02-.11.02-1.93 1.23-5.46 3.62-.51.35-.98.53-1.39.52-.46-.01-1.33-.26-1.98-.48-.8-.27-1.43-.42-1.37-.89.03-.25.38-.51 1.03-.78 4.04-1.76 6.74-2.92 8.09-3.48 3.85-1.6 4.64-1.88 5.17-1.89.11 0 .37.03.54.17.14.12.18.28.2.45-.02.07-.02.13-.03.19z"/>,
    phone: <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/>
  };
  return <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor">{icons[name]}</svg>;
};

const ProjectCard = ({ project, index }) => {
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);
  const cardRef = useRef(null);

  const handleMouseMove = (e) => {
    const rect = cardRef.current.getBoundingClientRect();
    setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div 
      className="project-card" 
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{ animationDelay: `${index * 0.15}s` }}
    >
      <div className="img-container">
        <img src={project.img} alt={project.title} />
        <div 
          className="magnetic-btn"
          style={{ 
            left: mousePos.x, 
            top: mousePos.y,
            opacity: isHovered ? 1 : 0,
            transform: `translate(-50%, -50%) scale(${isHovered ? 1 : 0.5})`
          }}
        >
          Смотреть
        </div>
      </div>
      <div className="project-details">
        <div>
          <span className="category-tag">{project.cat}</span>
          <h3>{project.title}</h3>
        </div>
        <span className="year">{project.year}</span>
      </div>
    </div>
  );
};

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showArchive, setShowArchive] = useState(false);

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];
  const projects = useMemo(() => ({
    featured: [
      { id: 'f1', title: "Проект айдентики", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=800" },
      { id: 'f2', title: "Веб-интерфейс", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=800" },
      { id: 'f3', title: "Логотип и стиль", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=800" },
    ],
    archive: [
      { id: 'a1', title: "Учебный логотип", cat: "Логотипы", year: 2024, img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?auto=format&fit=crop&q=80&w=800" },
      { id: 'a2', title: "Графическая работа", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1561070791-2526d30994b5?auto=format&fit=crop&q=80&w=800" },
    ]
  }), []);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) window.scrollTo({ top: el.offsetTop - 100, behavior: 'smooth' });
  };

  const filteredFeatured = projects.featured.filter(p => filter === 'Все' || p.cat === filter);

  return (
    <div className="app-container">
      <div className="grain-overlay"></div>

      <header className={`header-nav ${isScrolled ? 'nav-shrink' : ''}`}>
        <div className="nav-inner">
          <div className="logo-wrap">
            <span className="dot"></span>
            <span className="logo-text">АЛЕКСАНДРА БЛАГОДАТСКИХ</span>
          </div>
          <nav className="nav-links">
            <button onClick={() => scrollTo('projects')}>Работы</button>
            <button onClick={() => scrollTo('about')}>Инфо</button>
            <button onClick={() => scrollTo('contact')}>Связь</button>
          </nav>
        </div>
      </header>

      <section id="about" className="hero">
        <div className="hero-content">
          <div className="stagger-wrap">
            <h1 className="reveal-title">
              Создаю <i>эстетичный</i> <br/>
              дизайн с характером.
            </h1>
          </div>
          <p className="hero-sub">
            Разрабатываю визуальные решения для бизнеса: от логотипов до систем айдентики. 
            Помогаю брендам выделиться через продуманную графику.
          </p>
          <div className="filter-pills">
            {categories.map(cat => (
              <button 
                key={cat} 
                onClick={() => setFilter(cat)}
                className={`pill ${filter === cat ? 'active' : ''}`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </section>

      <main id="projects" className="main-content">
        <div className="grid-layout">
          {filteredFeatured.map((project, idx) => (
            <ProjectCard key={project.id} project={project} index={idx} />
          ))}
        </div>
      </main>

      <footer id="contact" className="footer">
        <div className="footer-top">
          <span className="f-label">Let's talk</span>
          <h2 className="f-title">Связаться со мной</h2>
          <div className="f-links">
            <a href="https://t.me/renraie" target="_blank" rel="noreferrer" className="contact-link">
              Telegram <span>@renraie</span>
            </a>
            <a href="tel:+79639960003" className="contact-link">
              Телефон <span>8 (963) 996-00-03</span>
            </a>
          </div>
        </div>
        <div className="footer-bottom">
          <p>© 2024—2026 Alexandra Blagodatskikh</p>
          <div className="status-badge">Available for work</div>
        </div>
      </footer>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;1,400&family=Plus+Jakarta+Sans:wght@300;400;600&display=swap');

        :root {
          --bg: #0a0a0c;
          --text: #f0f0f5;
          --accent: #ffb3d9;
          --dim: rgba(240, 240, 245, 0.4);
          --glass: rgba(255, 255, 255, 0.03);
        }

        body {
          margin: 0; background: var(--bg); color: var(--text);
          font-family: 'Plus Jakarta Sans', sans-serif;
          -webkit-font-smoothing: antialiased;
        }

        /* Шум на фоне */
        .grain-overlay {
          position: fixed; top: 0; left: 0; width: 100%; height: 100%;
          background: url('https://grainy-gradients.vercel.app/noise.svg');
          opacity: 0.04; pointer-events: none; z-index: 99;
        }

        /* Навигация */
        .header-nav {
          position: fixed; top: 0; width: 100%; z-index: 1000;
          padding: 30px 0; transition: 0.5s cubic-bezier(0.16, 1, 0.3, 1);
        }
        .nav-shrink { padding: 15px 0; background: rgba(10, 10, 12, 0.8); backdrop-filter: blur(20px); }
        .nav-inner { 
          max-width: 1400px; margin: 0 auto; padding: 0 40px;
          display: flex; justify-content: space-between; align-items: center;
        }
        .logo-text { font-size: 11px; letter-spacing: 0.3em; font-weight: 600; }
        .dot { display: inline-block; width: 6px; height: 6px; background: var(--accent); border-radius: 50%; margin-right: 12px; }

        .nav-links { display: flex; gap: 40px; }
        .nav-links button {
          background: none; border: none; color: var(--dim); cursor: pointer;
          font-size: 11px; text-transform: uppercase; letter-spacing: 0.1em; transition: 0.3s;
        }
        .nav-links button:hover { color: #fff; transform: translateY(-2px); }

        /* Hero */
        .hero { padding: 220px 40px 100px; max-width: 1400px; margin: 0 auto; }
        .reveal-title { 
          font-family: 'Playfair Display', serif; font-size: clamp(48px, 8vw, 110px); 
          line-height: 0.95; margin: 0 0 40px; font-weight: 400;
          animation: titleReveal 1.2s cubic-bezier(0.16, 1, 0.3, 1) both;
        }
        .reveal-title i { font-style: italic; color: var(--accent); }

        .hero-sub { 
          font-size: 20px; color: var(--dim); max-width: 600px; line-height: 1.6;
          animation: fadeInUp 1s both 0.4s;
        }

        .filter-pills { 
          display: flex; gap: 10px; margin-top: 60px; flex-wrap: wrap;
          animation: fadeInUp 1s both 0.6s;
        }
        .pill {
          padding: 12px 24px; border-radius: 100px; border: 1px solid rgba(255,255,255,0.1);
          background: var(--glass); color: var(--dim); font-size: 13px; cursor: pointer; transition: 0.4s;
        }
        .pill.active { background: var(--text); color: var(--bg); border-color: var(--text); }
        .pill:hover:not(.active) { border-color: var(--accent); color: var(--accent); }

        /* Сетка проектов */
        .main-content { max-width: 1400px; margin: 0 auto; padding: 100px 40px; }
        .grid-layout { display: grid; grid-template-columns: repeat(2, 1fr); gap: 100px 40px; }

        .project-card { opacity: 0; animation: fadeInUp 1s forwards; position: relative; }
        .img-container { 
          position: relative; border-radius: 24px; overflow: hidden; aspect-ratio: 16/10;
          background: #151518; cursor: none;
        }
        .img-container img { 
          width: 100%; height: 100%; object-fit: cover; transition: 1.5s cubic-bezier(0.16, 1, 0.3, 1);
        }
        .project-card:hover img { transform: scale(1.08); }

        /* Магнитная кнопка "Смотреть" */
        .magnetic-btn {
          position: absolute; width: 100px; height: 100px; background: var(--accent);
          border-radius: 50%; color: #000; display: flex; align-items: center; justify-content: center;
          font-size: 13px; font-weight: 600; pointer-events: none; z-index: 10;
          transition: transform 0.1s ease-out, opacity 0.3s;
        }

        .project-details { 
          display: flex; justify-content: space-between; align-items: flex-end; padding: 30px 10px;
        }
        .project-details h3 { font-family: 'Playfair Display', serif; font-size: 32px; font-weight: 400; margin: 0; }
        .category-tag { font-size: 11px; text-transform: uppercase; color: var(--accent); letter-spacing: 0.1em; display: block; margin-bottom: 8px; }
        .year { font-size: 13px; color: var(--dim); }

        /* Футер */
        .footer { background: #050507; padding: 140px 40px 60px; border-top: 1px solid rgba(255,255,255,0.05); }
        .footer-top { max-width: 1400px; margin: 0 auto; }
        .f-label { color: var(--accent); font-size: 13px; text-transform: uppercase; letter-spacing: 0.3em; }
        .f-title { font-family: 'Playfair Display', serif; font-size: clamp(40px, 6vw, 90px); font-weight: 400; margin: 20px 0 80px; }

        .f-links { display: flex; flex-direction: column; gap: 30px; }
        .contact-link { 
          font-size: 32px; text-decoration: none; color: var(--text); transition: 0.4s;
          display: flex; justify-content: space-between; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 20px;
        }
        .contact-link span { color: var(--dim); font-size: 24px; transition: 0.4s; }
        .contact-link:hover { color: var(--accent); padding-left: 20px; }
        .contact-link:hover span { color: var(--accent); transform: translateX(-20px); }

        .footer-bottom { 
          max-width: 1400px; margin: 100px auto 0; display: flex; justify-content: space-between;
          font-size: 12px; color: var(--dim);
        }
        .status-badge { color: #00ffaa; display: flex; align-items: center; gap: 8px; }
        .status-badge::before { content: ''; width: 6px; height: 6px; background: #00ffaa; border-radius: 50%; box-shadow: 0 0 10px #00ffaa; }

        /* Анимации */
        @keyframes titleReveal {
          from { opacity: 0; transform: translateY(60px) skewY(5deg); }
          to { opacity: 1; transform: translateY(0) skewY(0); }
        }
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(30px); }
          to { opacity: 1; transform: translateY(0); }
        }

        @media (max-width: 900px) {
          .grid-layout { grid-template-columns: 1fr; }
          .hero { padding-top: 160px; }
          .contact-link { font-size: 20px; }
          .contact-link span { font-size: 16px; }
        }
      `}</style>
    </div>
  );
};

export default App;
